#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string electMonitor(vector<string>& students, vector<string>& votes) {
        int n = students.size();

        // 如果票数多于全班人数，选举无效
        if (votes.size() > n) {
            return "Invalid election.";
        }

        unordered_map<string, int> nameCount;
        vector<string> candidates;

        // 生成符合重名规则的合法候选人姓名
        for (string name : students) {
            int cnt = nameCount[name];
            string realName;

            if (cnt == 0) {
                realName = name;
            } else {
                realName = name + to_string(cnt);
            }

            nameCount[name]++;
            candidates.push_back(realName);
        }

        unordered_set<string> candidateSet(candidates.begin(), candidates.end());
        unordered_map<string, int> voteCount;

        // 统计有效选票
        for (string vote : votes) {
            if (candidateSet.count(vote)) {
                voteCount[vote]++;
            }
        }

        // 没有有效票，选举失败
        if (voteCount.empty()) {
            return "Invalid election.";
        }

        string ans = "";
        int maxVotes = -1;

        // 找出票数最多的人，票数相同取字典序更小
        for (string name : candidates) {
            int cnt = voteCount[name];

            if (cnt > maxVotes || (cnt == maxVotes && name < ans)) {
                maxVotes = cnt;
                ans = name;
            }
        }

        return ans;
    }
};
