var electMonitor = function(students, votes) {
    var n = students.length;

    // 票数多于全班人数，选举无效
    if (votes.length > n) return "Invalid election.";

    // 生成符合重名规则的合法候选人姓名
    var nameCount = {};
    var candidates = [];
    for (var i = 0; i < n; i++) {
        var name = students[i];
        var cnt = nameCount[name] || 0;
        var realName;
        if (cnt === 0) {
            realName = name;
        } else {
            realName = name + cnt;
        }
        nameCount[name] = cnt + 1;
        candidates.push(realName);
    }

    // 构建候选人集合
    var candidateSet = {};
    for (var i = 0; i < candidates.length; i++) {
        candidateSet[candidates[i]] = true;
    }

    // 统计有效选票
    var voteCount = {};
    for (var i = 0; i < votes.length; i++) {
        var vote = votes[i];
        if (candidateSet[vote]) {
            voteCount[vote] = (voteCount[vote] || 0) + 1;
        }
    }

    // 没有有效票，选举失败
    if (Object.keys(voteCount).length === 0) return "Invalid election.";

    // 找出票数最多的人，票数相同取字典序更小
    var ans = "";
    var maxVotes = -1;
    for (var i = 0; i < candidates.length; i++) {
        var cnt = voteCount[candidates[i]] || 0;
        if (cnt > maxVotes || (cnt === maxVotes && candidates[i] < ans)) {
            maxVotes = cnt;
            ans = candidates[i];
        }
    }

    return ans;
};
