```c
#include <stdio.h>
#include <string.h>
#include <stdlib.h>

typedef struct {
    const char* name;
    int cnt;
} NC;

typedef struct {
    char* name;
    int cnt;
} VC;

char* electMonitor(char** students, int studentsSize, char** votes, int votesSize) {
    // 票数多于全班人数，选举无效
    if (votesSize > studentsSize) return "Invalid election.";

    // 动态分配候选人姓名统计表
    int ncCap = 256, ncSize = 0;
    NC* nameCount = (NC*)malloc(ncCap * sizeof(NC));
    int candCap = 256, candSize = 0;
    char** cands = (char**)malloc(candCap * sizeof(char*));

    // 生成符合重名规则的合法候选人姓名
    for (int i = 0; i < studentsSize; i++) {
        char* name = students[i];
        int idx = -1;
        for (int j = 0; j < ncSize; j++) {
            if (strcmp(nameCount[j].name, name) == 0) { idx = j; break; }
        }
        char tmp[256];
        if (idx == -1) {
            strcpy(tmp, name);
            if (ncSize >= ncCap) { ncCap *= 2; nameCount = (NC*)realloc(nameCount, ncCap * sizeof(NC)); }
            nameCount[ncSize].name = name;
            nameCount[ncSize].cnt = 1;
            ncSize++;
        } else {
            sprintf(tmp, "%s%d", name, nameCount[idx].cnt);
            nameCount[idx].cnt++;
        }
        if (candSize >= candCap) { candCap *= 2; cands = (char**)realloc(cands, candCap * sizeof(char*)); }
        cands[candSize] = (char*)malloc(strlen(tmp) + 1);
        strcpy(cands[candSize], tmp);
        candSize++;
    }

    // 统计有效选票
    int vcCap = 256, vcSize = 0;
    VC* voteCount = (VC*)malloc(vcCap * sizeof(VC));
    for (int i = 0; i < votesSize; i++) {
        char* vote = votes[i];
        int valid = 0;
        for (int j = 0; j < candSize; j++) {
            if (strcmp(cands[j], vote) == 0) { valid = 1; break; }
        }
        if (!valid) continue;
        int idx = -1;
        for (int j = 0; j < vcSize; j++) {
            if (strcmp(voteCount[j].name, vote) == 0) { idx = j; break; }
        }
        if (idx == -1) {
            if (vcSize >= vcCap) { vcCap *= 2; voteCount = (VC*)realloc(voteCount, vcCap * sizeof(VC)); }
            voteCount[vcSize].name = vote;
            voteCount[vcSize].cnt = 1;
            vcSize++;
        } else {
            voteCount[idx].cnt++;
        }
    }

    if (vcSize == 0) {
        for (int i = 0; i < candSize; i++) free(cands[i]);
        free(cands); free(nameCount); free(voteCount);
        return "Invalid election.";
    }

    // 找出票数最多的人，票数相同取字典序更小
    char* ans = "";
    int maxVotes = -1;
    for (int i = 0; i < candSize; i++) {
        int cnt = 0;
        for (int j = 0; j < vcSize; j++) {
            if (strcmp(voteCount[j].name, cands[i]) == 0) { cnt = voteCount[j].cnt; break; }
        }
        if (cnt > maxVotes || (cnt == maxVotes && (ans[0] == '\0' || strcmp(cands[i], ans) < 0))) {
            maxVotes = cnt;
            ans = cands[i];
        }
    }

    char* result = (char*)malloc(strlen(ans) + 1);
    strcpy(result, ans);
    for (int i = 0; i < candSize; i++) free(cands[i]);
    free(cands); free(nameCount); free(voteCount);
    return result;
}
